namespace BgControls.Windows.Input.Touch;/// <summary>/// 手势识别器工厂接口，用于定义手势识别器的创建逻辑及处理优先级./// </summary>public interface IGestureRecognizerFactory{    /// <summary>    /// Gets 处理优先级. 数值通常用于决定多个识别器共存时事件分发的先后顺序.    /// </summary>    int Priority { get; }    /// <summary>    /// 为指定的 UI 元素创建一个新的手势识别器实例.    /// </summary>    /// <param name="element">关联的 UI 元素.</param>    /// <returns>返回派生自 <see cref="GestureRecognizerBase"/> 的手势识别器实例接口.</returns>    GestureRecognizerBase CreateGestureRecognizer(UIElement element);    /// <summary>    /// 注册手势之间的状态转换逻辑或手势互斥规则.    /// </summary>    void RegisterGestureTransitions();}